// Handle Session TTL failure — GDPR data retention violation
const event = $input.first().json;

const result = {
  type: 'session_ttl_failure',
  severity: 'P1',
  userId: event.userId || 'UNKNOWN',
  sessionAge: event.sessionAge || 0,
  ttlLimit: event.ttlLimit || 3600,
  exceededBy: Math.max(0, (event.sessionAge || 0) - (event.ttlLimit || 3600)),
  dataExposed: event.dataExposed || false,
  timestamp: event.timestamp || new Date().toISOString(),
  actionRequired: 'FORCE_LOGOUT_ALL + SECURITY_INCIDENT_REPORT',
};

console.log(`[W22] 🔴 Session TTL Failure: User ${result.userId}, session age ${result.sessionAge}s exceeds ${result.ttlLimit}s limit`);

return [{ json: result }];
